mapper.select:
select t.*
  from t_fund_asset t


        and t.fund_name like concat('%',#{fundName},'%')


        and t.fund_code like concat('%',#{fundCode},'%')


        and t.fund_type in

            #{item}



        and t.asset_scale >= #{assetScale}


        and t.operation_mode = #{operationMode}


        and t.closed_end_days >= #{closedEndDays}


order by t.update_time desc

select *
  from t_fund_nav t


        and t.fund_code = #{fundCode}


        and t.nav_date >= #{beginTime}


        and t.nav_date <= #{endTime}


order by t.nav_date desc

select *
  from t_fund_manager_analysis t
where t.fund_code = #{param1}

select *
  from t_fund_holding t
where t.fund_code = #{param1}
  and t.owner = #{param2}

select *
  from t_fund_transaction t


        and t.fund_code = #{fundCode}


        and t.trade_date >= #{beginTime}


        and t.trade_date <= #{endTime}


        and t.owner = #{owner}


order by t.trade_date desc

select *
  from t_fund_dividend t


        and t.fund_code = #{fundCode}


        and t.dividend_date >= #{beginTime}


        and t.dividend_date <= #{endTime}


order by t.dividend_date desc

select *
  from t_fund_risk_performance t
where t.fund_code = #{param1}

select *
  from t_fund_portfolio t


        and t.fund_code = #{fundCode}


        and t.portfolio_date >= #{beginTime}


        and t.portfolio_date <= #{endTime}

WITH base AS (
SELECT unit_nav, nav_date
FROM t_fund_nav


        AND fund_code = #{fundCode}


        AND nav_date >= #{beginTime}


        AND nav_date <= #{endTime}


ORDER BY nav_date ASC
LIMIT 1
)
SELECT
t.nav_date,
t.unit_nav,
t.accumulated_nav,
t.daily_change_rate,
CASE
WHEN t.nav_date = (SELECT nav_date FROM base) THEN 0
ELSE ROUND((t.unit_nav - (SELECT unit_nav FROM base)) / (SELECT unit_nav FROM base) * 100, 2)
END AS sales_trend
FROM t_fund_nav t


        AND t.fund_code = #{fundCode}


        AND t.nav_date >= #{beginTime}


        AND t.nav_date <= #{endTime}


ORDER BY t.nav_date ASC

SELECT -- 最大日涨幅（%） MAX(daily_change_rate) AS maxDayIncrease, -- 最大日跌幅（%） MIN(daily_change_rate) AS maxDayDecrease, -- 超10涨幅天数（日涨跌幅 10） COUNT(CASE WHEN daily_change_rate > 10 THEN 1 END) AS overTenDayIncrease, -- 超10跌幅天数（日涨跌幅 -10） COUNT(CASE WHEN daily_change_rate < -10 THEN 1 END) AS overTenDayDecrease, -- 超10涨幅合计（%） COALESCE(SUM(CASE WHEN daily_change_rate > 10 THEN daily_change_rate ELSE 0 END), 0) AS overTenDayIncreaseSum, -- 超10跌幅合计（%） COALESCE(SUM(CASE WHEN daily_change_rate < -10 THEN daily_change_rate ELSE 0 END), 0) AS overTenDayDecreaseSum, -- 超5涨幅天数（日涨跌幅 > 5） COUNT(CASE WHEN daily_change_rate > 5 THEN 1 END) AS overFiveDayIncrease, -- 超5跌幅天数（日涨跌幅 -5） COUNT(CASE WHEN daily_change_rate < -5 THEN 1 END) AS overFiveDayDecrease, -- 超5涨幅合计（%） COALESCE(SUM(CASE WHEN daily_change_rate > 5 THEN daily_change_rate ELSE 0 END), 0) AS overFiveDayIncreaseSum, -- 超5跌幅合计（%） COALESCE(SUM(CASE WHEN daily_change_rate < -5 THEN daily_change_rate ELSE 0 END), 0) AS overFiveDayDecreaseSum, -- 上涨天数（日涨跌幅 > 0.01，避免浮点数0误差，下同） COUNT(CASE WHEN daily_change_rate > 0.01 THEN 1 END) AS increase, -- 下跌天数（日涨跌幅 -0.01） COUNT(CASE WHEN daily_change_rate < -0.01 THEN 1 END) AS decrease, -- 平盘天数（-0.01 = 日涨跌幅 = 0.01） COUNT(CASE WHEN daily_change_rate BETWEEN -0.01 AND 0.01 THEN 1 END) AS flat, -- 上涨合计（%） COALESCE(SUM(CASE WHEN daily_change_rate > 0.01 THEN daily_change_rate ELSE 0 END), 0) AS increaseSum, -- 下跌合计（%） COALESCE(SUM(CASE WHEN daily_change_rate < -0.01 THEN daily_change_rate ELSE 0 END), 0) AS decreaseSum, -- 总涨幅（%） COALESCE(SUM(daily_change_rate), 0) AS totalIncrease, -- 平均涨跌（%），保留4位小数 ROUND( COALESCE(SUM(daily_change_rate) / NULLIF(COUNT(CASE WHEN daily_change_rate IS NOT NULL THEN 1 END), 0), 0), 4 ) AS averageIncrease FROM t_fund_nav WHERE fund_code = #{fundCode}
AND nav_date >= #{beginTime}
AND nav_date <= #{endTime}
